  1	import * as React from 'react';
  2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  3	import {
  4	  Alert,
  5	  AlertActionCloseButton,
  6	  Button,
  7	  Radio,
  8	  Title,
  9	  Form,
 10	} from '@patternfly/react-core';
 11	import { MinusCircleIcon, PlusCircleIcon } from '@patternfly/react-icons';
 12	import { PlacementPolicy } from '../../../types';
 13	import { Action, State } from '../state';
 14	
 15	const PlacementPolicyPage: React.FC<PlacementPolicyPageProps> = ({
 16	  dispatch,
 17	  state,
 18	}) => {
 19	  const { t } = useCustomTranslation();
 20	
 21	  const { tier1Policy, tier2Policy } = state;
 22	  const [showHelp, setShowHelp] = React.useState(true);
 23	  const showTier2 = !!tier2Policy;
 24	
 25	  const onChange = (_checked: boolean, event) => {
 26	    const { name, value } = event.target;
 27	    if (name === 'placement-policy-1') {
 28	      dispatch({ type: 'setPlacementPolicyTier1', value });
 29	    } else if (name === 'placement-policy-2') {
 30	      dispatch({ type: 'setPlacementPolicyTier2', value });
 31	    }
 32	  };
 33	  return (
 34	    <div className="nb-create-bc-step-page">
 35	      {showHelp && (
 36	        <Alert
 37	          isInline
 38	          variant="info"
 39	          title={t('What is a Placement Policy?')}
 40	          className="nb-create-bc-step-page__info"
 41	          actionClose={
 42	            <AlertActionCloseButton onClose={() => setShowHelp(false)} />
 43	          }
 44	        >
 45	          <p>
 46	            {t(
 47	              'Data placement capabilities are built as a multi-layer structure here are the layers bottom-up:'
 48	            )}
 49	          </p>
 50	          <ul>
 51	            <li>
 52	              {t(
 53	                'Spread Tier - list of BackingStores aggregates the storage of multiple stores.'
 54	              )}
 55	            </li>
 56	            <li>
 57	              {t(
 58	                'Mirroring Tier - list of spread-layers async-mirroring to all mirrors with locality optimization (will allocate on the closest region to the source endpoint). Mirroring requires at least two BackingStores.'
 59	              )}
 60	            </li>
 61	          </ul>
 62	          {t(
 63	            'The number of replicas can be configured via the NooBaa management console.'
 64	          )}
 65	        </Alert>
 66	      )}
 67	      <Form className="nb-create-bc-step-page-form">
 68	        <Title
 69	          size="xl"
 70	          headingLevel="h2"
 71	          className="nb-bc-step-page-form__title"
 72	        >
 73	          {t('Tier 1 - Policy Type')}
 74	        </Title>
 75	        <Radio
 76	          data-test="placement-policy-spread1"
 77	          value={PlacementPolicy.Spread}
 78	          isChecked={tier1Policy === PlacementPolicy.Spread}
 79	          onChange={(event, checked: boolean) => onChange(checked, event)}
 80	          id="radio-1"
 81	          label={t('Spread')}
 82	          name="placement-policy-1"
 83	        />
 84	        <p className="nb-create-bc-step-page-form__element--light-text">
 85	          {t(
 86	            'Spreading the data across the chosen resources. By default a replica of one copy is used and does not include failure tolerance in case of resource failure.'
 87	          )}
 88	        </p>
 89	        <Radio
 90	          data-test="placement-policy-mirror1"
 91	          value={PlacementPolicy.Mirror}
 92	          isChecked={tier1Policy === PlacementPolicy.Mirror}
 93	          onChange={(event, checked: boolean) => onChange(checked, event)}
 94	          id="radio-2"
 95	          label={t('Mirror')}
 96	          name="placement-policy-1"
 97	        />
 98	        <p className="nb-create-bc-step-page-form__element--light-text">
 99	          {t(
100	            'Full duplication of the data in each chosen resource. By default a replica of one copy per location is used. Includes failure tolerance in case of resource failure.'
101	          )}
102	        </p>
103	      </Form>
104	      {!showTier2 && (
105	        <Button
106	          variant="link"
107	          icon={<PlusCircleIcon />}
108	          onClick={() =>
109	            dispatch({
110	              type: 'setPlacementPolicyTier2',
111	              value: PlacementPolicy.Spread,
112	            })
113	          }
114	          isInline
115	          data-testid="add-tier-btn"
116	          data-test="add-tier-btn"
117	        >
118	          {t('Add Tier')}
119	        </Button>
120	      )}
121	      {showTier2 && (
122	        <Form className="nb-create-bc-step-page-form">
123	          <Title
124	            headingLevel="h2"
125	            size="xl"
126	            className="nb-bc-step-page-form__title"
127	          >
128	            {t('Tier 2 - Policy type')}
129	            <Button
130	              variant="link"
131	              icon={<MinusCircleIcon />}
132	              onClick={() =>
133	                dispatch({ type: 'setPlacementPolicyTier2', value: null })
134	              }
135	              isInline
136	            >
137	              {t('Remove Tier')}
138	            </Button>
139	          </Title>
140	          <Radio
141	            data-test="placement-policy-spread2"
142	            value={PlacementPolicy.Spread}
143	            isChecked={tier2Policy === PlacementPolicy.Spread}
144	            onChange={(event, checked: boolean) => onChange(checked, event)}
145	            id="radio-3"
146	            label={t('Spread')}
147	            name="placement-policy-2"
148	          />
149	          <p className="nb-create-bc-step-page-form__element--light-text">
150	            {t(
151	              'Spreading the data across the chosen resources does not include failure tolerance in case of resource failure.'
152	            )}
153	          </p>
154	          <Radio
155	            data-test="placement-policy-mirror2"
156	            value={PlacementPolicy.Mirror}
157	            isChecked={tier2Policy === PlacementPolicy.Mirror}
158	            onChange={(event, checked: boolean) => onChange(checked, event)}
159	            id="radio-4"
160	            label={t('Mirror')}
161	            name="placement-policy-2"
162	          />
163	          <p className="nb-create-bc-step-page-form__element--light-text">
164	            {t(
165	              'Full duplication of the data in each chosen resource includes failure tolerance in cause of resource failure.'
166	            )}
167	          </p>
168	        </Form>
169	      )}
170	    </div>
171	  );
172	};
173	
174	export default PlacementPolicyPage;
175	
176	type PlacementPolicyPageProps = {
177	  dispatch: React.Dispatch<Action>;
178	  state: State;
179	};

